import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None  # Indicates for the truck to wait or return to depot

    weights = np.zeros(len(unvisited_customers))
    urgency_factor = 2.0 / (1 + np.exp(-0.1 * (len(unvisited_customers) - 10)))

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer)
        dist_to_depot = distance(depot_pos, customer)

        # Closer distance incentivized by a steeper exponential decay for current position
        distance_weight = np.exp(-0.5 * dist_to_customer)

        # Adding an urgency factor to prioritize remaining customers as they dwindle
        urgency_bonus = urgency_factor * np.exp(-0.03 * dist_to_depot)

        congestion_penalty = 0
        for other_truck in all_truck_pos:
            if distance(other_truck, customer) < 1.5 * dist_to_customer:
                congestion_penalty += 0.5 / (1 + np.exp(3 * (distance(other_truck, customer) - dist_to_customer)))

        # Balance weights with both positives and the congestion negatives
        weights[i] = distance_weight + urgency_bonus - congestion_penalty

    best_node = np.argmax(weights)

    return best_node
